"use client";

import { useRef } from "react";
import { useGSAP } from "@gsap/react";
import { gsap } from "@/utils/gsap";
import Hero from "./Hero";

export default function HeroBanner() {
  const container = useRef<HTMLDivElement>(null);

  useGSAP(() => {
    const hero = container.current;
    const content = hero?.querySelector(".hero-content-wrapper");
    const image = hero?.querySelector("img");

    if (!hero || !content || !image) return;

    // Hero expand animation
    gsap.fromTo(
      hero,
      {
        width: "92%",
        height: "80vh",
        borderRadius: "40px",
      },
      {
        width: "100%",
        height: "100%",
        borderRadius: "0px",
        scrollTrigger: {
          trigger: hero,
          start: "top top",
          end: "bottom top",
          scrub: true,
        },
      },
    );

    // Move hero text upward
    gsap.to(content, {
      y: () => -window.innerHeight * 0.35,
      scrollTrigger: {
        trigger: hero,
        start: "top top",
        end: "bottom top",
        scrub: true,
      },
    });

    // Background parallax
    gsap.to(image, {
      yPercent: -10,
      scrollTrigger: {
        trigger: hero,
        start: "top top",
        end: "bottom top",
        scrub: true,
      },
    });
  }, []);

  return (
    <section className="relative bg-slate-950 h-[200vh]">
      <div className="sticky top-0 h-screen flex items-center justify-center">
        <div
          ref={container}
          className="relative h-screen w-full overflow-hidden will-change-transform"
        >
          <img
            src="/video-1-1920.jpg"
            alt=""
            className="absolute inset-0 w-full h-full object-contain"
          />

          <div className="absolute inset-0 bg-black/40" />

          <div className="hero-content-wrapper absolute inset-0 flex items-center justify-center text-white px-16">
            <Hero />
          </div>
        </div>
      </div>
    </section>
  );
}
